-- Modelos técnicos dinâmicos extraídos dos HTMLs de referência SIGEBAP

alter table public.ordens_servico
  add column if not exists modelo_relatorio_id uuid,
  add column if not exists tipo_manutencao text;

create table if not exists public.modelos_relatorio (
  id uuid primary key default gen_random_uuid(),
  codigo text not null unique,
  titulo text not null,
  equipamento_tipo text not null,
  tipo_manutencao text not null check (tipo_manutencao in ('corretiva','preventiva','preditiva')),
  area text,
  source_html text,
  resumo text,
  versao integer not null default 1,
  ativo boolean not null default true,
  metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz
);

create table if not exists public.campos_relatorio (
  id uuid primary key default gen_random_uuid(),
  modelo_id uuid not null references public.modelos_relatorio(id) on delete cascade,
  chave text not null,
  label text not null,
  tipo text not null check (tipo in ('texto','numero','textarea','select','checklist','foto','assinatura')),
  grupo text not null default 'dados',
  obrigatorio boolean not null default false,
  ordem integer not null default 0,
  opcoes jsonb not null default '[]'::jsonb,
  metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (modelo_id, chave)
);

create table if not exists public.respostas_relatorio (
  id uuid primary key default gen_random_uuid(),
  os_id uuid not null references public.ordens_servico(id) on delete cascade,
  modelo_id uuid not null references public.modelos_relatorio(id) on delete restrict,
  equipamento_id uuid references public.equipamentos(id) on delete set null,
  ativo_nome text,
  tipo_manutencao text not null check (tipo_manutencao in ('corretiva','preventiva','preditiva')),
  status text not null default 'rascunho' check (status in ('rascunho','enviado_supervisor','aprovado_supervisor','nao_conforme','cancelado')),
  respostas jsonb not null default '{}'::jsonb,
  fotos_obrigatorias jsonb not null default '[]'::jsonb,
  observacoes text,
  enviado_por uuid references public.usuarios(id) on delete set null,
  enviado_em timestamptz,
  validado_por uuid references public.usuarios(id) on delete set null,
  validado_em timestamptz,
  motivo_nao_conformidade text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz,
  unique (os_id, modelo_id)
);

do $$
begin
  alter table public.ordens_servico
    add constraint ordens_servico_modelo_relatorio_id_fkey
    foreign key (modelo_relatorio_id) references public.modelos_relatorio(id) on delete set null;
exception
  when duplicate_object then null;
end $$;

create index if not exists idx_modelos_relatorio_tipo on public.modelos_relatorio(tipo_manutencao, area) where deleted_at is null;
create index if not exists idx_campos_relatorio_modelo on public.campos_relatorio(modelo_id, ordem);
create index if not exists idx_respostas_relatorio_os on public.respostas_relatorio(os_id, status) where deleted_at is null;

alter table public.modelos_relatorio enable row level security;
alter table public.campos_relatorio enable row level security;
alter table public.respostas_relatorio enable row level security;

drop policy if exists "modelos_relatorio_read" on public.modelos_relatorio;
create policy "modelos_relatorio_read" on public.modelos_relatorio for select using (deleted_at is null and public.can_read_operational());
drop policy if exists "modelos_relatorio_admin" on public.modelos_relatorio;
create policy "modelos_relatorio_admin" on public.modelos_relatorio for all using (public.current_app_role() in ('anon','supervisor','gerencia','diretoria','service_role')) with check (true);

drop policy if exists "campos_relatorio_read" on public.campos_relatorio;
create policy "campos_relatorio_read" on public.campos_relatorio for select using (public.can_read_operational());
drop policy if exists "campos_relatorio_admin" on public.campos_relatorio;
create policy "campos_relatorio_admin" on public.campos_relatorio for all using (public.current_app_role() in ('anon','supervisor','gerencia','diretoria','service_role')) with check (true);

drop policy if exists "respostas_relatorio_read" on public.respostas_relatorio;
create policy "respostas_relatorio_read" on public.respostas_relatorio for select using (deleted_at is null and public.can_read_operational());
drop policy if exists "respostas_relatorio_write" on public.respostas_relatorio;
create policy "respostas_relatorio_write" on public.respostas_relatorio for all using (public.current_app_role() in ('anon','tecnico','supervisor','gerencia','diretoria','service_role')) with check (true);

